#!/usr/bin/env node
/**
 * validate-adj-coverage.mjs — Surface high-frequency Adjacent Vocabulary
 * chips that don't yet have their own page.
 *
 * For every chip-cn that appears across content/**.md without a matching
 * built page, emit one INFO finding per chip when it appears on N or more
 * pages. These are candidate vocab entries — the chip is being authored
 * frequently enough that promoting it to a real page would meaningfully
 * improve the cross-link graph.
 *
 * Reads data/adj-index.json (generated by build.mjs).
 * Writes findings into data/_admin/findings.json under category:'relations'.
 */

import fs from 'node:fs';
import path from 'node:path';
import { createFinding, mergeFindings, reportFindings } from './lib/findings.mjs';

const ROOT = path.resolve(new URL('.', import.meta.url).pathname, '..');
const indexPath = path.join(ROOT, 'data', 'adj-index.json');

if (!fs.existsSync(indexPath)) {
  console.error('validate-adj-coverage: data/adj-index.json missing — run `npm run build` first.');
  process.exit(1);
}

const index = JSON.parse(fs.readFileSync(indexPath, 'utf8'));

// Threshold tuning (calibrated against the current adj-index distribution,
// where the natural ceiling for non-built chips is ~4 appearances):
//   - 4+ appearances → strong candidate, INFO finding
//   - 2-3 appearances → optional candidate, lighter INFO framing
//   - 1 → noise, ignore
const STRONG_THRESHOLD = 4;
const SOFT_THRESHOLD = 2;

const findings = [];

const candidates = Object.values(index).filter(c => !c.hasPage && c.count >= SOFT_THRESHOLD);

// Group strong candidates into one finding (a single dashboard row is more
// actionable than 30 separate ones); soft candidates become an inventory
// finding with a slightly different message.
const strong = candidates.filter(c => c.count >= STRONG_THRESHOLD);
const soft = candidates.filter(c => c.count >= SOFT_THRESHOLD && c.count < STRONG_THRESHOLD);

if (strong.length > 0) {
  const sample = strong.slice(0, 30).map(c => `${c.cn} (${c.py}, ${c.count}×)`).join(' · ');
  const more = strong.length > 30 ? ` … +${strong.length - 30} more` : '';
  findings.push(createFinding({
    level: 'INFO',
    category: 'relations',
    file: 'data/adj-index.json',
    msg: `${strong.length} adj-chip vocab term${strong.length === 1 ? '' : 's'} appear on ${STRONG_THRESHOLD}+ pages without a built entry — strong candidates for promotion to vocab pages: ${sample}${more}`,
    fix: 'For each, decide whether to author as content/vocab/<slug>.md or content/characters/<slug>.md. After publishing, the chips automatically become clickable links on every page that references them.',
  }));
}

if (soft.length > 0) {
  const sample = soft.slice(0, 20).map(c => `${c.cn}(${c.count})`).join(', ');
  const more = soft.length > 20 ? ` … +${soft.length - 20} more` : '';
  findings.push(createFinding({
    level: 'INFO',
    category: 'relations',
    file: 'data/adj-index.json',
    msg: `${soft.length} adj-chip vocab term${soft.length === 1 ? '' : 's'} appear on ${SOFT_THRESHOLD}-${STRONG_THRESHOLD - 1} pages without a built entry (softer candidates): ${sample}${more}`,
    fix: 'Optional: promote to a page if the term is meaningful in its own right. Otherwise leave as chip-only vocabulary.',
  }));
}

// Inventory finding (always emitted): total chip vocab universe.
const total = Object.keys(index).length;
const linked = Object.values(index).filter(c => c.hasPage).length;
findings.push(createFinding({
  level: 'INFO',
  category: 'relations',
  file: 'data/adj-index.json',
  msg: `adj-chip inventory: ${total} unique chip terms across all pages, ${linked} (${total ? Math.round(linked / total * 100) : 0}%) currently auto-linked to existing entries`,
}));

reportFindings('validate-adj-coverage', findings);
mergeFindings(ROOT, findings, ['relations']);

// All findings are INFO; never fail the build on this.
process.exit(0);
